    public DetalhesLivroDialog(Livro obj, boolean e) {
        initComponents();
        txtID.setText(String.valueOf(obj.getId()));
        txtTitulo.setText(obj.getTitulo());
        txtAutor.setText(obj.getAutor());
        txtEditora.setText(obj.getEditora());
        txtAno.setYear(obj.getAno_publicacao());
        jCGenero.setSelectedItem(obj.getGenero());
        txtPagina.setText(String.valueOf(obj.getPaginas()));
        txtIdioma.setText(obj.getIdioma());
        txtQtd.setText(String.valueOf(obj.getQuantidade()));
        JDData.setDate(obj.getData_cadastro());
        
         if (e) {
            setTitle("Editar Aluno");
            habilitarCampos(true);
            btnSalvarAtualizacao.setVisible(true);
        } else {
            setTitle("Detalhes do Aluno");
            habilitarCampos(false);
            btnSalvarAtualizacao.setVisible(false);
        }
    }
    
    private void habilitarCampos(boolean estado) {
        txtTitulo.setEditable(estado);
        txtAutor.setEditable(estado);
        txtAno.setEnabled(estado);
        txtIdioma.setEditable(estado);
        jCGenero.setEnabled(estado);
        txtEditora.setEditable(estado);
        txtID.setEditable(false);
        JDData.setEnabled(estado);
        txtQtd.setEditable(estado);
        txtPagina.setEditable(estado);
    }
    
    public DetalhesLivroDialog() {
    initComponents();
    }


