    private void btnSalvarAtualizacaoActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnSalvarAtualizacaoActionPerformed
        // TODO add your handling code here:
            try {
                Livro l = new Livro();
                l.setAno_publicacao(txtAno.getYear());
                l.setAutor(txtAutor.getText());
                l.setData_cadastro(new java.sql.Date(JDData.getDate().getTime()));
                l.setEditora(txtEditora.getText());
                l.setGenero((String) jCGenero.getSelectedItem());
                l.setIdioma(txtIdioma.getText());
                l.setPaginas(Integer.parseInt(txtPagina.getText()));
                l.setQuantidade(Integer.parseInt(txtQtd.getText()));
                l.setTitulo(txtTitulo.getText());
                l.setId(Integer.parseInt(txtID.getText()));
                LivroDAO dao = new LivroDAO();
                dao.atualizar(l);
            } catch (ClassNotFoundException ex) {
                Logger.getLogger(DetalhesLivroDialog.class.getName()).log(Level.SEVERE, null, ex);
            }
    }//GEN-LAST:event_btnSalvarAtualizacaoActionPerformed

